import anthropic
import json

client = anthropic.Anthropic()

PRICING_WATCH_PROMPT = """
You are a FinOps analyst monitoring Claude API pricing.
Given the following pricing page excerpt, extract any price changes compared
to the known baseline prices and output a JSON object.

Baseline prices (per million tokens):
- claude-sonnet input: $3.00, output: $15.00
- claude-haiku input: $0.25, output: $1.25
- claude-opus input: $15.00, output: $75.00

Pricing page excerpt:
{excerpt}

Output JSON format:
{{
  "changes_detected": true/false,
  "models": [
    {{
      "model": "model-name",
      "input_price_old": 3.00,
      "input_price_new": 2.50,
      "output_price_old": 15.00,
      "output_price_new": 15.00,
      "input_multiplier": 0.833,
      "output_multiplier": 1.0,
      "effective_date": "YYYY-MM-DD or null"
    }}
  ]
}}
"""

def parse_pricing_announcement(excerpt: str) -> dict:
    """Use Claude to extract structured price change data from a pricing page."""
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": PRICING_WATCH_PROMPT.format(excerpt=excerpt)
        }],
    )
    text = response.content[0].text
    # Extract JSON block if wrapped in markdown
    if "```json" in text:
        text = text.split("```json")[1].split("```")[0].strip()
    elif "```" in text:
        text = text.split("```")[1].split("```")[0].strip()
    return json.loads(text)
